    public static class CertificateLoader
    {
        public static X509Certificate2 LoadFromStore(StoreName storeName, StoreLocation storeLocation, string thumbprint, bool requirePrivateKey)
        {
            if (string.IsNullOrWhiteSpace(thumbprint))
            {
                throw new ConfigurationErrorsException("Certificate thumbprint is required.");
            }

            var normalized = thumbprint.Replace(" ", string.Empty).ToUpperInvariant();

            using (var store = new X509Store(storeName, storeLocation))
            {
                store.Open(OpenFlags.ReadOnly);
                var found = store.Certificates.Find(X509FindType.FindByThumbprint, normalized, false);
                if (found.Count == 0)
                {
                    throw new ConfigurationErrorsException("Certificate not found: " + normalized);
                }

                foreach (var cert in found)
                {
                    if (!requirePrivateKey || cert.HasPrivateKey)
                    {
                        return cert;
                    }
                }
            }

            throw new ConfigurationErrorsException("Certificate found but private key requirement not satisfied: " + normalized);
        }
    }

